// raiseError is a helper function which collects the current location of the parse and wraps the given cause.
func (p *Parser) raiseError(cause error) error {
	return &Error{
		Token:      p.scanner.Token(),
		ByteOffset: p.scanner.ByteOffset(),
		Line:       p.scanner.Line(),
		Column:     p.scanner.Column(),
		Lexeme:     p.scanner.Lexeme(),
		FilePath:   p.scanner.FilePath(),
		Cause:      cause,
	}
}

// allocateNodes provides and arena allocator for slices of Node.
func (p *Parser) allocateNodes(n int) []Node {
	if p.arenaAllocatorTop+n > len(p.arenaAllocator) {
		p.arenaAllocator = make([]Node, max(n, 16*1024))
		p.arenaAllocatorTop = 0
	}
	nodes := p.arenaAllocator[p.arenaAllocatorTop : p.arenaAllocatorTop+n]
	p.arenaAllocatorTop += n
	return nodes
}

func (p *Parser) state0() error {
	terminal := p.scanner.Token()
	switch terminal {
	// package
	case TokenPackage:
		// Shift action
		p.stateStack = append(p.stateStack, 1)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	// test_basic_lit
	case TokenTestBasicLit:
		// Shift action
		p.stateStack = append(p.stateStack, 2)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	// test_expression
	case TokenTestExpression:
		// Shift action
		p.stateStack = append(p.stateStack, 3)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	// test_type
	case TokenTestType:
		// Shift action
		p.stateStack = append(p.stateStack, 4)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	// test_statement
	case TokenTestStatement:
		// Shift action
		p.stateStack = append(p.stateStack, 5)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	// test_decl
	case TokenTestDecl:
		// Shift action
		p.stateStack = append(p.stateStack, 6)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	default:
		// Reduce: SourceFile -> %empty
		nextState, err := p.gotoAfterNonterminalSourcefile(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol: NewNonterminal(NonterminalSourcefile),
		}
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

func (p *Parser) state1() error {
	terminal := p.scanner.Token()
	switch terminal {
	// identifier
	case TokenIdentifier:
		// Shift action
		p.stateStack = append(p.stateStack, 9)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	default:
		return p.raiseError(fmt.Errorf("unexpected token %s", terminal))
	}
}

