func (p *Parser) state31() error {
	terminal := p.scanner.Token()
	switch terminal {
	default:
		// Reduce: PrimaryExpr -> Operand
		p.stateStack = p.stateStack[:len(p.stateStack)-1]
		nextState, err := p.gotoAfterNonterminalPrimaryexpr(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol:   NewNonterminal(NonterminalPrimaryexpr),
			Children: p.allocateNodes(1),
		}
		copy(newNode.Children, p.nodeStack[len(p.nodeStack)-1:])
		p.nodeStack = p.nodeStack[:len(p.nodeStack)-1]
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

