func (p *Parser) state149() error {
	terminal := p.scanner.Token()
	switch terminal {
	// right_paren
	case TokenRightParen:
		// Reduce: ConversionType -> ArrayType
		p.stateStack = p.stateStack[:len(p.stateStack)-1]
		nextState, err := p.gotoAfterNonterminalConversiontype(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol:   NewNonterminal(NonterminalConversiontype),
			Children: p.allocateNodes(1),
		}
		copy(newNode.Children, p.nodeStack[len(p.nodeStack)-1:])
		p.nodeStack = p.nodeStack[:len(p.nodeStack)-1]
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	// left_paren
	case TokenLeftParen:
		// Shift action
		p.stateStack = append(p.stateStack, 189)
		p.nodeStack = append(p.nodeStack, Node{
			Symbol: NewTerminal(terminal),
			Lexeme: p.scanner.Lexeme(),
		})
		p.scanner.Next()
		return nil
	default:
		// Reduce: LiteralType -> ArrayType
		p.stateStack = p.stateStack[:len(p.stateStack)-1]
		nextState, err := p.gotoAfterNonterminalLiteraltype(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol:   NewNonterminal(NonterminalLiteraltype),
			Children: p.allocateNodes(1),
		}
		copy(newNode.Children, p.nodeStack[len(p.nodeStack)-1:])
		p.nodeStack = p.nodeStack[:len(p.nodeStack)-1]
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

