func (p *Parser) state256() error {
	terminal := p.scanner.Token()
	switch terminal {
	default:
		// Reduce: ZeroOrMoreTypeSpecSemicolon -> %empty
		nextState, err := p.gotoAfterNonterminalZeroormoretypespecsemicolon(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol: NewNonterminal(NonterminalZeroormoretypespecsemicolon),
		}
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

func (p *Parser) state257() error {
	terminal := p.scanner.Token()
	switch terminal {
	default:
		// Reduce: TypeDecl -> type AliasDecl
		p.stateStack = p.stateStack[:len(p.stateStack)-2]
		nextState, err := p.gotoAfterNonterminalTypedecl(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol:   NewNonterminal(NonterminalTypedecl),
			Children: p.allocateNodes(2),
		}
		copy(newNode.Children, p.nodeStack[len(p.nodeStack)-2:])
		p.nodeStack = p.nodeStack[:len(p.nodeStack)-2]
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

