func (p *Parser) state409() error {
	terminal := p.scanner.Token()
	switch terminal {
	default:
		// Reduce: IncDecStmtNoBrace -> ExpressionNoBrace increment
		p.stateStack = p.stateStack[:len(p.stateStack)-2]
		nextState, err := p.gotoAfterNonterminalIncdecstmtnobrace(p.stateStack[len(p.stateStack)-1])
		if err != nil {
			return err
		}
		p.stateStack = append(p.stateStack, nextState)
		newNode := Node{
			Symbol:   NewNonterminal(NonterminalIncdecstmtnobrace),
			Children: p.allocateNodes(2),
		}
		copy(newNode.Children, p.nodeStack[len(p.nodeStack)-2:])
		p.nodeStack = p.nodeStack[:len(p.nodeStack)-2]
		p.nodeStack = append(p.nodeStack, newNode)
		return nil
	}
}

